import{_ as e,o as l,c as d,ae as a}from"./chunks/framework.BEtfQoF7.js";const p=JSON.parse('{"title":"Claude Code Desktop에서 반복 작업 예약하기","description":"Claude Code Desktop에서 예약 작업을 설정하여 일일 코드 리뷰, 의존성 감사, 아침 브리핑 등을 자동으로 반복 실행하세요.","frontmatter":{"title":"Claude Code Desktop에서 반복 작업 예약하기","description":"Claude Code Desktop에서 예약 작업을 설정하여 일일 코드 리뷰, 의존성 감사, 아침 브리핑 등을 자동으로 반복 실행하세요."},"headers":[],"relativePath":"desktop-scheduled-tasks.md","filePath":"desktop-scheduled-tasks.md","lastUpdated":1776205703000}'),o={name:"desktop-scheduled-tasks.md"};function s(r,t,n,i,c,h){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="claude-code-desktop에서-반복-작업-예약하기" tabindex="-1">Claude Code Desktop에서 반복 작업 예약하기 <a class="header-anchor" href="#claude-code-desktop에서-반복-작업-예약하기" aria-label="Permalink to &quot;Claude Code Desktop에서 반복 작업 예약하기&quot;">​</a></h1><p>기본적으로 예약 작업은 사용자가 선택한 시간과 빈도에 맞춰 자동으로 새 세션을 시작합니다. 일일 코드 리뷰, 의존성 업데이트 확인, 캘린더와 메일함에서 정보를 가져오는 아침 브리핑 등 반복적인 작업에 활용하세요.</p><h2 id="예약-옵션-비교" tabindex="-1">예약 옵션 비교 <a class="header-anchor" href="#예약-옵션-비교" aria-label="Permalink to &quot;예약 옵션 비교&quot;">​</a></h2><p>Claude Code는 반복 작업을 예약하는 세 가지 방법을 제공합니다:</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;"><a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드</a></th><th style="text-align:left;"><a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">Desktop</a></th><th style="text-align:left;"><a href="/claude-code-docs-ko/scheduled-tasks.html"><code>/loop</code></a></th></tr></thead><tbody><tr><td style="text-align:left;">실행 위치</td><td style="text-align:left;">Anthropic 클라우드</td><td style="text-align:left;">사용자 머신</td><td style="text-align:left;">사용자 머신</td></tr><tr><td style="text-align:left;">머신 켜져 있어야 함</td><td style="text-align:left;">아니오</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">세션 열려 있어야 함</td><td style="text-align:left;">아니오</td><td style="text-align:left;">아니오</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">재시작 후에도 유지</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td><td style="text-align:left;">아니오 (세션 범위)</td></tr><tr><td style="text-align:left;">로컬 파일 접근</td><td style="text-align:left;">아니오 (새로 클론)</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">MCP 서버</td><td style="text-align:left;">작업별로 구성된 커넥터</td><td style="text-align:left;"><a href="/claude-code-docs-ko/mcp.html">설정 파일</a> 및 커넥터</td><td style="text-align:left;">세션에서 상속</td></tr><tr><td style="text-align:left;">권한 프롬프트</td><td style="text-align:left;">아니오 (자율 실행)</td><td style="text-align:left;">작업별 구성 가능</td><td style="text-align:left;">세션에서 상속</td></tr><tr><td style="text-align:left;">사용자 정의 일정</td><td style="text-align:left;">CLI에서 <code>/schedule</code>로 설정</td><td style="text-align:left;">예</td><td style="text-align:left;">예</td></tr><tr><td style="text-align:left;">최소 간격</td><td style="text-align:left;">1시간</td><td style="text-align:left;">1분</td><td style="text-align:left;">1분</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>머신 없이도 안정적으로 실행되어야 하는 작업에는 <strong>클라우드 작업</strong>을 사용하세요. 로컬 파일과 도구에 접근해야 할 때는 <strong>Desktop 작업</strong>을 사용하세요. 세션 중 빠른 폴링에는 **<code>/loop</code>**을 사용하세요.</p></div><p>Schedule 페이지는 두 가지 종류의 작업을 지원합니다:</p><ul><li><strong>로컬 작업</strong>: 사용자 머신에서 실행됩니다. 로컬 파일과 도구에 직접 접근할 수 있지만, Desktop 앱이 열려 있고 컴퓨터가 깨어 있어야 실행됩니다.</li><li><strong>원격 작업</strong>: Anthropic이 관리하는 클라우드 인프라에서 실행됩니다. 컴퓨터가 꺼져 있어도 계속 실행되지만, 로컬 체크아웃이 아닌 저장소의 새 클론에 대해 작업합니다.</li></ul><p>두 종류 모두 동일한 작업 그리드에 표시됩니다. <strong>New task</strong>를 클릭하여 어떤 종류를 생성할지 선택하세요. 이 페이지의 나머지 내용은 로컬 작업에 대해 다룹니다. 원격 작업에 대해서는 <a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드 예약 작업</a>을 참조하세요.</p><p>로컬 작업의 놓친 실행 및 보충 실행 동작에 대한 자세한 내용은 <a href="#예약-작업-실행-방식">예약 작업 실행 방식</a>을 참조하세요.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>기본적으로 로컬 예약 작업은 커밋되지 않은 변경 사항을 포함하여 작업 디렉토리의 현재 상태에 대해 실행됩니다. 프롬프트 입력에서 worktree 토글을 활성화하면 <a href="/claude-code-docs-ko/desktop.html#work-in-parallel-with-sessions">병렬 세션</a>과 동일한 방식으로 각 실행에 격리된 Git worktree를 제공합니다.</p></div><h2 id="예약-작업-만들기" tabindex="-1">예약 작업 만들기 <a class="header-anchor" href="#예약-작업-만들기" aria-label="Permalink to &quot;예약 작업 만들기&quot;">​</a></h2><p>로컬 예약 작업을 만들려면 사이드바에서 <strong>Schedule</strong>을 클릭하고, <strong>New task</strong>를 클릭한 다음 <strong>New local task</strong>를 선택하세요. 다음 필드를 구성합니다:</p><table tabindex="0"><thead><tr><th>필드</th><th>설명</th></tr></thead><tbody><tr><td>Name</td><td>작업의 식별자입니다. 소문자 케밥 케이스로 변환되어 디스크의 폴더 이름으로 사용됩니다. 작업 간에 고유해야 합니다.</td></tr><tr><td>Description</td><td>작업 목록에 표시되는 간단한 요약입니다.</td></tr><tr><td>Prompt</td><td>작업이 실행될 때 Claude에게 전송되는 지시사항입니다. 프롬프트 박스에 메시지를 작성하는 것과 동일한 방식으로 작성하세요. 프롬프트 입력에는 모델, 권한 모드, 작업 폴더, worktree 관련 컨트롤도 포함됩니다.</td></tr><tr><td>Frequency</td><td>작업 실행 빈도입니다. 아래의 <a href="#빈도-옵션">빈도 옵션</a>을 참조하세요.</td></tr></tbody></table><p>아무 세션에서든 원하는 내용을 설명하여 작업을 만들 수도 있습니다. 예를 들어, &quot;매일 아침 9시에 실행되는 일일 코드 리뷰를 설정해줘.&quot;</p><h2 id="빈도-옵션" tabindex="-1">빈도 옵션 <a class="header-anchor" href="#빈도-옵션" aria-label="Permalink to &quot;빈도 옵션&quot;">​</a></h2><p>빈도 드롭다운에서 프리셋을 선택하거나, 피커에서 제공하지 않는 일정은 Claude에게 요청하세요:</p><ul><li><strong>Manual</strong>: 일정 없음, <strong>Run now</strong>을 클릭할 때만 실행됩니다. 필요할 때 트리거하는 프롬프트를 저장하는 데 유용합니다</li><li><strong>Hourly</strong>: 매시간 실행됩니다. 각 작업은 API 트래픽을 분산하기 위해 정시로부터 최대 10분의 고정 오프셋을 갖습니다</li><li><strong>Daily</strong>: 시간 선택기가 표시되며, 기본값은 현지 시간 오전 9:00입니다</li><li><strong>Weekdays</strong>: Daily와 동일하지만 토요일과 일요일을 건너뜁니다</li><li><strong>Weekly</strong>: 시간 선택기와 요일 선택기가 표시됩니다</li></ul><p>피커에서 제공하지 않는 간격(15분마다, 매월 1일 등)의 경우, Desktop 세션에서 Claude에게 일정을 설정하도록 요청하세요. 자연어를 사용하세요. 예를 들어, &quot;6시간마다 모든 테스트를 실행하는 작업을 예약해줘.&quot;</p><h2 id="예약-작업-실행-방식" tabindex="-1">예약 작업 실행 방식 <a class="header-anchor" href="#예약-작업-실행-방식" aria-label="Permalink to &quot;예약 작업 실행 방식&quot;">​</a></h2><p>로컬 예약 작업은 사용자 머신에서 실행됩니다. Desktop은 앱이 열려 있는 동안 매분 일정을 확인하고, 작업이 예정된 시간이 되면 수동 세션과 독립적으로 새 세션을 시작합니다. 각 작업은 예정 시간 이후 API 트래픽을 분산하기 위해 최대 10분의 고정 지연을 갖습니다. 이 지연은 결정적입니다: 동일한 작업은 항상 동일한 오프셋에서 시작됩니다.</p><p>작업이 실행되면 데스크톱 알림을 받고 사이드바의 <strong>Scheduled</strong> 섹션 아래에 새 세션이 나타납니다. 열어서 Claude가 수행한 작업을 확인하거나, 변경 사항을 검토하거나, 권한 프롬프트에 응답할 수 있습니다. 세션은 다른 세션과 동일하게 작동합니다: Claude는 파일을 편집하고, 명령을 실행하고, 커밋을 생성하고, 풀 리퀘스트를 열 수 있습니다.</p><p>작업은 Desktop 앱이 실행 중이고 컴퓨터가 깨어 있는 동안에만 실행됩니다. 예정된 시간에 컴퓨터가 절전 모드에 있으면 실행이 건너뛰어집니다. 유휴 절전을 방지하려면 설정의 <strong>Desktop app → General</strong>에서 <strong>Keep computer awake</strong>를 활성화하세요. 노트북 덮개를 닫으면 여전히 절전 모드로 전환됩니다. 컴퓨터가 꺼져 있을 때도 실행해야 하는 작업에는 <a href="/claude-code-docs-ko/web-scheduled-tasks.html">원격 작업</a>을 사용하세요.</p><h2 id="놓친-실행" tabindex="-1">놓친 실행 <a class="header-anchor" href="#놓친-실행" aria-label="Permalink to &quot;놓친 실행&quot;">​</a></h2><p>앱이 시작되거나 컴퓨터가 깨어나면, Desktop은 지난 7일 동안 각 작업의 놓친 실행이 있는지 확인합니다. 있다면, Desktop은 가장 최근에 놓친 시간에 대해 정확히 한 번의 보충 실행을 시작하고 그보다 오래된 것은 버립니다. 6일을 놓친 일일 작업은 깨어났을 때 한 번 실행됩니다. Desktop은 보충 실행이 시작될 때 알림을 표시합니다.</p><p>프롬프트를 작성할 때 이점을 염두에 두세요. 오전 9시로 예약된 작업이 컴퓨터가 하루 종일 절전 모드였다면 오후 11시에 실행될 수 있습니다. 시간이 중요하다면 프롬프트 자체에 가드레일을 추가하세요. 예를 들어: &quot;오늘의 커밋만 검토해줘. 오후 5시 이후라면 리뷰를 건너뛰고 놓친 것의 요약만 게시해줘.&quot;</p><h2 id="예약-작업-권한" tabindex="-1">예약 작업 권한 <a class="header-anchor" href="#예약-작업-권한" aria-label="Permalink to &quot;예약 작업 권한&quot;">​</a></h2><p>각 작업에는 자체 권한 모드가 있으며, 작업을 만들거나 편집할 때 설정합니다. <code>~/.claude/settings.json</code>의 허용 규칙도 예약 작업 세션에 적용됩니다. 작업이 Ask 모드에서 실행되고 권한이 없는 도구를 실행해야 하는 경우, 승인할 때까지 실행이 중단됩니다. 세션은 사이드바에 열려 있어 나중에 응답할 수 있습니다.</p><p>중단을 방지하려면 작업을 만든 후 <strong>Run now</strong>을 클릭하고 권한 프롬프트를 확인한 다음, 각각에 대해 &quot;always allow&quot;를 선택하세요. 해당 작업의 향후 실행에서는 프롬프트 없이 동일한 도구를 자동 승인합니다. 작업의 세부 페이지에서 이러한 승인을 검토하고 취소할 수 있습니다.</p><h2 id="예약-작업-관리" tabindex="-1">예약 작업 관리 <a class="header-anchor" href="#예약-작업-관리" aria-label="Permalink to &quot;예약 작업 관리&quot;">​</a></h2><p><strong>Schedule</strong> 목록에서 작업을 클릭하면 세부 페이지가 열립니다. 여기에서 다음을 수행할 수 있습니다:</p><ul><li><strong>Run now</strong>: 다음 예정 시간을 기다리지 않고 즉시 작업을 시작합니다</li><li><strong>Toggle repeats</strong>: 작업을 삭제하지 않고 예약 실행을 일시 중지하거나 재개합니다</li><li><strong>Edit</strong>: 프롬프트, 빈도, 폴더 또는 기타 설정을 변경합니다</li><li><strong>Review history</strong>: 컴퓨터가 절전 모드여서 건너뛴 것을 포함하여 모든 과거 실행을 확인합니다</li><li><strong>Review allowed permissions</strong>: <strong>Always allowed</strong> 패널에서 이 작업에 대해 저장된 도구 승인을 확인하고 취소합니다</li><li><strong>Delete</strong>: 작업을 제거하고 생성된 모든 세션을 아카이브합니다</li></ul><p>Desktop 세션에서 Claude에게 요청하여 작업을 관리할 수도 있습니다. 예를 들어, &quot;dependency-audit 작업을 일시 중지해줘&quot;, &quot;standup-prep 작업을 삭제해줘&quot;, &quot;내 예약 작업을 보여줘.&quot;</p><p>작업의 프롬프트를 디스크에서 편집하려면 <code>~/.claude/scheduled-tasks/&lt;task-name&gt;/SKILL.md</code>를 열어보세요 (설정된 경우 <a href="/claude-code-docs-ko/env-vars.html"><code>CLAUDE_CONFIG_DIR</code></a> 아래). 파일은 <code>name</code>과 <code>description</code>에 대한 YAML frontmatter를 사용하며, 본문이 프롬프트입니다. 변경 사항은 다음 실행에 적용됩니다. 일정, 폴더, 모델, 활성화 상태는 이 파일에 없습니다: Edit 양식을 통하거나 Claude에게 요청하여 변경하세요.</p><h2 id="관련-리소스" tabindex="-1">관련 리소스 <a class="header-anchor" href="#관련-리소스" aria-label="Permalink to &quot;관련 리소스&quot;">​</a></h2><ul><li><a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드 예약 작업</a>: 컴퓨터가 꺼져 있어도 Anthropic 관리 인프라에서 실행되는 작업 예약</li><li><a href="/claude-code-docs-ko/scheduled-tasks.html">일정에 따라 프롬프트 실행</a>: CLI에서 <code>/loop</code>을 사용한 세션 범위 예약</li><li><a href="/claude-code-docs-ko/github-actions.html">Claude Code GitHub Actions</a>: 머신 대신 CI에서 Claude를 일정에 따라 실행</li><li><a href="/claude-code-docs-ko/desktop.html">Claude Code Desktop 사용하기</a>: 전체 Desktop 앱 가이드</li></ul>',36)])])}const g=e(o,[["render",s]]);export{p as __pageData,g as default};
